import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a VA loan?", a: "A VA loan is a mortgage backed by the Department of Veterans Affairs for eligible veterans, service members, and some surviving spouses." },
  { q: "Who qualifies for a VA loan?", a: "Eligibility depends on military service history, duty status, discharge type, and VA certificate of eligibility rules." },
  { q: "What is the VA funding fee?", a: "The VA funding fee is a one-time program fee that can often be financed into the loan amount." },
  { q: "Do VA loans require PMI?", a: "VA loans do not require monthly private mortgage insurance, which can lower monthly cost compared with low-down conventional loans." },
  { q: "What is the VA loan limit?", a: "Many eligible borrowers with full entitlement do not have a VA-imposed loan limit, but lenders still review income, credit, and affordability." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function pmt(principal: number, rate: number, years: number) { const r = rate / 100 / 12; const n = years * 12; return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n)); }
function fundingRate(tier: string, downPct: number) { if (tier === "Reserves") return 0.0225; if (downPct >= 10) return tier === "First use" ? 0.0125 : 0.014; if (downPct >= 5) return tier === "First use" ? 0.015 : 0.0165; return tier === "First use" ? 0.0215 : 0.033; }
function va(home: number, downPct: number, rate: number, years: number, tier: string) { const down = home * downPct / 100; const base = home - down; const fee = base * fundingRate(tier, downPct); const loan = base + fee; const monthly = pmt(loan, rate, years); return { down, fee, loan, monthly }; }
function fhaCost(home: number) { const base = home * .965; return pmt(base + base * .0175, 6.5, 30) + base * .0055 / 12; }
function convCost(home: number, downPct: number) { const loan = home * (1 - downPct / 100); return pmt(loan, 6.5, 30) + (downPct < 20 ? loan * .006 / 12 : 0); }

export default function VAMortgageCalculator() {
  useCurrencyVersion();
  const [home, setHome] = useState(350000);
  const [downPct, setDownPct] = useState(0);
  const [years, setYears] = useState(30);
  const [rate, setRate] = useState(6.25);
  const [tier, setTier] = useState("First use");
  const result = useMemo(() => va(home, downPct, rate, years, tier), [home, downPct, rate, years, tier]);
  const rows = [
    ["VA 0% down", "0%", va(350000, 0, 6.25, 30, "First use").fee, va(350000, 0, 6.25, 30, "First use").monthly, "Yes"],
    ["VA 5% down", "5%", va(350000, 5, 6.25, 30, "First use").fee, va(350000, 5, 6.25, 30, "First use").monthly, "Yes"],
    ["FHA 3.5% down", "3.5%", 350000 * .965 * .0175, fhaCost(350000), "No"],
    ["Conventional 5% down", "5%", 350000 * .95 * .006 / 12, convCost(350000, 5), "No"],
    ["Conventional 20% down", "20%", 0, convCost(350000, 20), "Yes"],
  ] as const;
  return (
    <>
      <SEOHead title="Free VA Mortgage Calculator Online - Calculate VA Loan Payments and Funding Fee Instantly | CalcHive" description="Free online VA mortgage calculator. Calculate VA loan monthly payments, funding fee and compare to FHA and conventional loans for any home price instantly. 100% free, no signup required." canonical="/va-mortgage-calculator" keywords="free VA mortgage calculator, VA loan calculator free online, VA home loan payment calculator free, calculate VA funding fee free, veteran mortgage calculator free" category="Financial Calculators" breadcrumbName="Free VA Mortgage Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free VA Mortgage Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate VA loan payments, funding fee, total loan amount, and compare common mortgage types.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home price</label><input type="number" value={home} onChange={(e) => setHome(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment (%)</label><input type="number" value={downPct} onChange={(e) => setDownPct(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Funding fee tier</label><select value={tier} onChange={(e) => setTier(e.target.value)} className={inputClass}><option>First use</option><option>Subsequent use</option><option>Reserves</option></select></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly VA Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">VA funding fee</p><p className="text-lg font-extrabold text-foreground">{money(result.fee)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total loan amount</p><p className="text-lg font-extrabold text-foreground">{money(result.loan)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Down payment</p><p className="text-lg font-extrabold text-foreground">{money(result.down)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate VA Loan Payments and Funding Fee for Free</h2><p className="text-muted-foreground leading-relaxed">VA loan cost combines principal, interest, and the VA funding fee if it is financed into the loan.</p><h2 className="text-2xl font-bold text-foreground">VA Loan Benefits vs FHA and Conventional Loans</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">VA Loan vs FHA vs Conventional - $350,000 Home</caption><thead className="bg-muted/60"><tr>{["Loan Type", "Down Payment", "Funding Fee/MIP", "Monthly Payment", "No PMI", "Total Cost 30yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row[0]}><td className="py-2.5 px-3 font-semibold">{row[0]}</td><td className="py-2.5 px-3">{row[1]}</td><td className="py-2.5 px-3">{money(Number(row[2]))}</td><td className="py-2.5 px-3">{money(Number(row[3]))}</td><td className="py-2.5 px-3">{row[4]}</td><td className="py-2.5 px-3">{money(Number(row[3]) * 360)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free VA Mortgage Calculator for Veterans and Military</h2><p className="text-muted-foreground leading-relaxed">Use this VA calculator as a planning estimate before comparing official lender quotes and VA eligibility details.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/va-mortgage-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


